var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰","JPN":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n付録: 対象者観察","ENG":"CCN No. CSM002M000755-09\\n<color=#ffd34c>Class 3 Subject</color> Access Approval Documents\\nAppendix: Subject Observation","TWN":"(TWN)CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헉......! 허억......!","JPN":"はっと......!許億......!","ENG":"Huff...! Ngh...!","TWN":"(TWN)헉......! 허억......!"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"젠장, 망할 늙다리 같으니....\\n왜 한 대도 안 맞는 거야...!","JPN":"くそ、滅ぶ老いぼれのようなの....\\nなぜ一台も当たらないことなの...!","ENG":"Damn it, you stubborn old fossil...\\nWhy can't I land a single hit...!","TWN":"(TWN)젠장, 망할 늙다리 같으니....\\n왜 한 대도 안 맞는 거야...!"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷 씨는 당장 공격하는 순간만 중요하게 생각하고 있습니다.","JPN":"バーネットさんは今すぐ攻撃する瞬間だけ重要に思っています。","ENG":"Mr. Burnet, you are only focusing on the moment of attack.","TWN":"(TWN)버넷 씨는 당장 공격하는 순간만 중요하게 생각하고 있습니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L8_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"체스를 생각하십시오.\\n두 수 앞을 생각해야 국면을 뒤집을 수 있습니다.","JPN":"チェスを思ってください。\\n二首前を思ってこそ局面を覆すことができます。","ENG":"Think of it as chess.\\nYou must think two moves ahead to turn the tide.","TWN":"(TWN)체스를 생각하십시오.\\n두 수 앞을 생각해야 국면을 뒤집을 수 있습니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"웃기고 자빠졌네!!","JPN":"笑わせて転がったな!!","ENG":"Don't make me laugh!!","TWN":"(TWN)웃기고 자빠졌네!!"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"빌어먹을...... 또 졌어.......","JPN":"畜生......また負けた.......","ENG":"Damn it...... I did it again.......","TWN":"(TWN)빌어먹을...... 또 졌어......."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"수고하셨습니다, 버넷 씨.\\n이런 추세라면 조만간 실전에도 투입될 수 있을 겁니다.","JPN":"苦労しました、バーネットさん。\\nこのような傾向なら早いうちに実戦にも投入されることができるはずです。","ENG":"Good work, Mr. Burnet.\\nAt this rate, you'll be ready for actual combat soon.","TWN":"(TWN)수고하셨습니다, 버넷 씨.\\n이런 추세라면 조만간 실전에도 투입될 수 있을 겁니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"흥. 그래 봤자 저번처럼 조수 노릇이나 하겠지.","JPN":"ふん。そう見たところでこの前のように助手役もする。","ENG":"Hmph. Even then, I'll probably just be an assistant like last time.","TWN":"(TWN)흥. 그래 봤자 저번처럼 조수 노릇이나 하겠지."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 뭐야.... 악령 들렸다는 아저씨였나?\\n그때도 현관문이나 지키게 했잖아.","JPN":"その何なの....悪霊聞こえたというおじさんだったか?\\nあの時も玄関ドアも守らせたんじゃないの。","ENG":"What was it... that guy who was supposedly possessed?\\nYou just had me guarding the entrance then.","TWN":"(TWN)그 뭐야.... 악령 들렸다는 아저씨였나?\\n그때도 현관문이나 지키게 했잖아."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L17_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"현장의 분위기가 어떤지 피부로 느껴지지 않았습니까?","JPN":"現場の雰囲気がどうなのか肌で感じられなかったのですか?","ENG":"Didn't you feel the atmosphere of that site with your own skin?","TWN":"(TWN)현장의 분위기가 어떤지 피부로 느껴지지 않았습니까?"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L18_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"대 침식전 현장은 버넷 씨가 아는 것보다 끔찍합니다.\\n이터니움 실드도, 워치도 두려움을 막아 주진 않습니다.","JPN":"大侵食前現場はバーネットさんが分かるのより無残です。\\nエタニウムシールドも、ウォッチも恐れを防いでくれないです。","ENG":"Erosion incursion sites are far more horrific than you know.\\nNeither Eternium Shields nor Watches can keep fear at bay.","TWN":"(TWN)대 침식전 현장은 버넷 씨가 아는 것보다 끔찍합니다.\\n이터니움 실드도, 워치도 두려움을 막아 주진 않습니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"됐다 그래. 어차피 그놈들도 죽일 수 있는 건데 뭐가 무섭다고.","JPN":"なったそう。どのみちあいつも殺すことができる濃いが何が恐ろしいと。","ENG":"Fine, whatever. I can kill those things anyway, so what's there to be afraid of.","TWN":"(TWN)됐다 그래. 어차피 그놈들도 죽일 수 있는 건데 뭐가 무섭다고."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"좋은 배짱입니다.\\n실전을 치른 뒤에도 지금 같은 모습을 보여 주길 바랍니다.","JPN":"良い度胸です。\\n実戦を行った後にも今同じ姿を見せてくれてほしいです。","ENG":"That's good spirit.\\nI hope you maintain that attitude after experiencing real combat.","TWN":"(TWN)좋은 배짱입니다.\\n실전을 치른 뒤에도 지금 같은 모습을 보여 주길 바랍니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L21_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 훈련을 마치기 전에 한 가지 말씀드리겠습니다.","JPN":"それでは訓練を終える前に一つの申し上げます。","ENG":"Then before we conclude training, allow me to say one thing.","TWN":"(TWN)그럼 훈련을 마치기 전에 한 가지 말씀드리겠습니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"엉? 또 뭐?","JPN":"オング?また何?","ENG":"Huh? What is it now?","TWN":"(TWN)엉? 또 뭐?"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L23_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷 씨의 실력은 예전보다 많이 향상됐습니다.","JPN":"バーネットさんの実力はこの前よりたくさん向上しました。","ENG":"Your skills have improved significantly compared to before.","TWN":"(TWN)버넷 씨의 실력은 예전보다 많이 향상됐습니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L24_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"빠르고 간결한 공격으로 제 움직임을 봉쇄하려고 의도했다는 점이 기억에 남는군요.","JPN":"はやくて簡潔な攻撃で私の動きを封鎖しようと意図したという点が記憶に残りますね。","ENG":"I recall that you intended to seal my movements with swift, concise attacks.","TWN":"(TWN)빠르고 간결한 공격으로 제 움직임을 봉쇄하려고 의도했다는 점이 기억에 남는군요."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그거. 계속 안 맞으니까 약올라서 휘둘렀긴 한데....","JPN":"あ、それ。ずっと当たらないからしゃくにさわって振り回したことは一所....","ENG":"Ah, that. I got frustrated that I kept missing, so I just swung wildly....","TWN":"(TWN)아, 그거. 계속 안 맞으니까 약올라서 휘둘렀긴 한데...."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L26_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"어떻게 했는지는 상관없습니다. 할 수 있다는 사실을 확인했으면 충분합니다.","JPN":"どうしたかは構わないです。できるという事実を確認したら十分です。","ENG":"How you did it is irrelevant. It's enough that you've proven you can do it.","TWN":"(TWN)어떻게 했는지는 상관없습니다. 할 수 있다는 사실을 확인했으면 충분합니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":".......","JPN":".......","ENG":".......","TWN":"(TWN)......."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L28_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"잘 가다듬으면 상대의 접근을 막고 싸울 수 있을 겁니다.\\n거리를 두고 싸워야 하는 버넷 씨에게는 좋은 방식입니다.","JPN":"よく整えれば相手の接近を防いで戦うことができるはずです。\\n距離を置いて戦わなければならないバーネットさんには良い方式です。","ENG":"If you refine it, you'll be able to block the enemy's approach and fight.\\nIt's an excellent method for you, Mr. Burnet, who must fight at range.","TWN":"(TWN)잘 가다듬으면 상대의 접근을 막고 싸울 수 있을 겁니다.\\n거리를 두고 싸워야 하는 버넷 씨에게는 좋은 방식입니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L29_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"실전에서는 스스로 터득한 장점이야말로 믿음직스러운 동료입니다.\\n앞으로도 그렇게 정진해 주시길 바라겠습니다. ","JPN":"実戦では自ら悟った長所こそ頼もしい同僚です。\\n今後もそのように精進してお願いします。","ENG":"In real combat, the strengths you discover yourself are your most trustworthy allies.\\nPlease continue to improve in that manner.","TWN":"(TWN)실전에서는 스스로 터득한 장점이야말로 믿음직스러운 동료입니다.\\n앞으로도 그렇게 정진해 주시길 바라겠습니다. "},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"애꾸눈 영감 말이 맞네......","JPN":"独眼お爺さん言葉が当たるのね......","ENG":"The one-eyed geezer was right......","TWN":"(TWN)애꾸눈 영감 말이 맞네......"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L31_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"모건 경이 무슨 얘기를 했습니까?","JPN":"モーガン頃が何の話をしましたか?","ENG":"What did Inspector Morgan say?","TWN":"(TWN)모건 경이 무슨 얘기를 했습니까?"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 가정교사라고 하더라고.\\n영감 말대로 가르쳐 주는 건 잘한다 싶어서.","JPN":"いや、家庭教師と言っていたって。\\nお爺さん言葉通り教えてくれるのは上手であると思って。","ENG":"No, he said you're like a private tutor.\\nI figured you were good at teaching, just like the geezer said.","TWN":"(TWN)아니, 가정교사라고 하더라고.\\n영감 말대로 가르쳐 주는 건 잘한다 싶어서."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L33_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 전달도 끝났으니 계속 훈련을 진행하겠습니다.","JPN":"それでは伝達も終わったからずっと訓練を進行します。","ENG":"Then since the message has been relayed, we shall continue training.","TWN":"(TWN)그럼 전달도 끝났으니 계속 훈련을 진행하겠습니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 아니 왜?! 방금 마친다더니!","JPN":"何?いやなぜ?!今終えるといったら!","ENG":"What? No, why?! You just said we were finishing!","TWN":"(TWN)뭐? 아니 왜?! 방금 마친다더니!"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L35_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"모건 경의 나쁜 점을 배우지 않도록 예방하는 겁니다.\\n생각해 보니 그 인간은 좋은 점이 없군요.","JPN":"モーガン頃の短所を学ばないように予防するでしょう。\\n考えてみたらその人間は長所がないですね。","ENG":"It's to prevent you from learning Inspector Morgan's bad habits.\\nCome to think of it, that man has no redeeming qualities.","TWN":"(TWN)모건 경의 나쁜 점을 배우지 않도록 예방하는 겁니다.\\n생각해 보니 그 인간은 좋은 점이 없군요."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L36_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 시작하겠습니다.","JPN":"それでは始めます。","ENG":"Then let us begin.","TWN":"(TWN)그럼 시작하겠습니다."},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 이 늙다리 성질머리가!\\n야, 잠깐 타임......!","JPN":"いや、この老いぼれ性質頭家!\\nだけは、少しタイム......!","ENG":"No, you stubborn old fossil!\\nHey, time out......!","TWN":"(TWN)아니, 이 늙다리 성질머리가!\\n야, 잠깐 타임......!"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}}]`);export{e as default};